import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{r as u,o as e,c as a,d,a as l,b as r,e as n}from"./app-02133217.js";const o={},h=l("h1",{id:"数据结构",tabindex:"-1"},[l("a",{class:"header-anchor",href:"#数据结构","aria-hidden":"true"},"#"),r(" 数据结构")],-1),t=n('<p><a href="../../mark-map/ds-map.html" target="_blank">在线预览</a></p><h2 id="基础入门" tabindex="-1"><a class="header-anchor" href="#基础入门" aria-hidden="true">#</a> 基础入门</h2><h3 id="基本概念" tabindex="-1"><a class="header-anchor" href="#基本概念" aria-hidden="true">#</a> 基本概念</h3><ul><li><p>数据</p><ul><li>信息的载体</li><li>客观事物属性的数、字符以及所有能够输入到计算机包中并且被计算机程序识别和处理的集合</li></ul></li><li><p>数据元素</p><ul><li>数据的基本单位</li><li>一个数据元素由若干个数据项组成</li><li>数据项是构成数组元素的最小单位，且不可分割</li></ul></li><li><p>数据对象</p><ul><li>具有相同性质的数据元素的集合</li><li>数据的子集</li></ul></li><li><p>数据类型</p><ul><li>原子类型：不可再分的数据类型</li><li>结构类型：可以分解成若干分量（成分）的数据类型</li><li>抽象数据类型：抽象出具组织和其相关的操作</li></ul></li><li><p>抽象数据类型（ADT）</p><ul><li>定义：一个数学模型以及定义在该模型上的一组操作</li><li>特点：与计算机内部如何表示和实现是没有关系</li><li>作用：数据封装和信息隐藏，让实现与使用相分离</li><li>注意：不论内部结构如何变化，只要其数学特性不变，就不会影响到外部的使用</li></ul></li></ul><h3 id="数据结构-三要素" tabindex="-1"><a class="header-anchor" href="#数据结构-三要素" aria-hidden="true">#</a> 数据结构（三要素）</h3><ul><li><p>逻辑结构</p><ul><li>线性结构：线性表、栈、队列、串、数组...</li><li>非线性结构：树、图、集合...</li><li>集合：除了“同属于一个集合”的关系外，别无其他关系。</li><li>线性结构：只存在一对一的关系。</li><li>树形结构：存在一对多的关系。</li><li>图状结构和网状结构：存在多对多的关系。</li></ul></li><li><p>存储（物理）结构</p><ul><li><p>顺序存储</p><ul><li><p>逻辑上相邻的元素存储在物理位置上也相邻的存储单元里，元素之间的关系由存储单元的邻接关系来体现</p></li><li><p>优点</p><ul><li>可以实现随机存取</li><li>元素占用最少的存储空间</li></ul></li><li><p>缺点</p><ul><li>只能使用相邻的一整块存储单元，依赖于物理结构相邻</li><li>容易产生外部碎片</li></ul></li></ul></li><li><p>链式存储</p><ul><li><p>与顺序存储不同，链式存储不要求逻辑上相邻的元素在物理位置上也相邻</p></li><li><p>优点</p><ul><li>不会出现碎片现象</li><li>充分利用所有存储单元</li></ul></li><li><p>缺点</p><ul><li>除了存储元素外，还需要额外存储指针，会占用额外的存储空间（结合数据库索引学习）</li><li>链式存储，只能实现顺序存取，不能实现随机存取（指针的遍历）</li></ul></li></ul></li><li><p>索引存储</p><ul><li><p>存放数据元素和元素间关系的存储方式，在存储元素信息的同时，还需要建立附加的索引表</p></li><li><p>优点</p><ul><li>检索快（就好比字典有了目录，查询就很快了）</li></ul></li><li><p>缺点</p><ul><li>增加了索引表，占用较多的存储空间（典型的空间换时间策略）</li><li>增加、删除数据时，需要对应修改索引表，花费更多时间</li></ul></li></ul></li><li><p>散列（Hash）存储</p><ul><li><p>根据元素的关键字直接通过散列（Hash）函数计算出元素的存储地址。</p></li><li><p>优点</p><ul><li>检索快</li><li>添加、删除元素结点操作快（获取元素地址直接，整体时间就少了）</li></ul></li><li><p>缺点</p><ul><li>非常依赖于散列函数</li><li>会出现散列冲突（主要依赖与散列函数，散列函数不好就很容易出现散列冲突）</li><li>出现散列冲突时，解决冲突就会增加时间和空间上的开销</li></ul></li></ul></li></ul></li><li><p>数据的运算</p><ul><li>运算的定义：针对逻辑结构，指出运算的功能</li><li>运算的实现：针对存储结构，指出运算的具体操作步骤</li></ul></li></ul><h3 id="算法与算法评价" tabindex="-1"><a class="header-anchor" href="#算法与算法评价" aria-hidden="true">#</a> 算法与算法评价</h3><ul><li><p>算法</p><ul><li><p>定义</p><ul><li>对特定问题求解步骤的一种描述</li><li>是指令的有序集合</li><li>每一条指令表示一个或多个操作</li></ul></li><li><p>五大特性</p><ul><li>有穷性：执行有穷步后结束、在有穷时间内完成</li><li>确定性：每条指令的含义明确，不会产生二义性，对相同的输入只能得出相同的结果</li><li>可行性：算法中描述的操作都是可以通过已经实现的基本运算执行有限次来实现的</li><li>输入：有零个或者多个输入，输入取决于某个特定的对象的集合</li><li>输出：有一个或者多个输出，输出是和输入有着某种特定关系的量</li></ul></li><li><p>好算法追求的目标</p><ul><li><p>正确性：需要正确的解决求解问题</p></li><li><p>可读性：便于理解</p></li><li><p>健壮性：在输入非法数据时，算法也能适当地做出反应或进行处理，而不会产生莫名奇妙的输出结果</p></li><li><p>效率与低存储量需求</p><ul><li>效率：算法执行的时间---&gt;时间复杂度</li><li>存储量需求：算法那执行过程中所有要的最大存储空间---&gt;空间复杂度</li></ul></li></ul></li></ul></li><li><p>算法的评价</p><ul><li><p>程序语句频度：程序语句在算法中被重复执行的次数</p></li><li><p>时间复杂度O(n)</p><ul><li>最坏空间复杂度：最坏情况下，算法的时间复杂度</li><li>平均空间复杂度：所有可能输入实例在同等概率出现的情况下，算法的期望运行时间</li><li>最好空间复杂度：最好的情况下，算法的时间复杂度</li></ul></li><li><p>空间复杂度S(n)</p><ul><li>用来定义算法运行过程中需要耗费的存储空间</li><li>渐进空间复杂度也被称为空间复杂度 记作：S(n)=O(g(n))</li></ul></li></ul></li></ul><h2 id="线性表" tabindex="-1"><a class="header-anchor" href="#线性表" aria-hidden="true">#</a> 线性表</h2><h3 id="定义和基本操作" tabindex="-1"><a class="header-anchor" href="#定义和基本操作" aria-hidden="true">#</a> 定义和基本操作</h3><ul><li><p>基本概念</p><ul><li><p>定义：线性表是具有相同数据类型的n（n≥0）个数据元素的有限序列</p></li><li><p>逻辑特性</p><ul><li>除表头元素外，线性表中每个元素有且仅有一个</li><li>除表尾元素外，线性表中每个元素有且仅有一个直接后继</li></ul></li><li><p>基本特点</p><ul><li>元素个数有限</li><li>逻辑上具有顺序性</li><li>每个元素都是单个元素</li><li>数据类型都相同，元素存储空间大小一致</li><li>元素具有抽象性，只讨论逻辑关系</li></ul></li></ul></li><li><p>基本操作</p><ul><li>InitList(&amp;L)： 初始化表。构造空的线性表</li><li>Length(L)：获取表的长度。返回线性表L的长度，即表中的数据元素个数</li><li>LocateElem(L,e)：按值查找操作。在表L中国查找具有给定关键字的元素</li><li>GetElem(L,i)：按位查找操作。获取表中第i个位置的元素的值</li><li>ListInsert(&amp;L,i,e)：插入操作。在表的第i个位置上插入指定元素e</li><li>ListDelete(&amp;L,i,&amp;e)：删除操作。删除表中第i个位置的元素，并用e返回删除元素的值</li><li>PrintList(L)：输出操作。按照前后顺序（如：1、2....n）输出线性表的所有元素值</li><li>Empty(L)：判空操作。当表L为空，则返回true，否则返回false</li><li>DestoryList(&amp;L)：销毁操作。将线性表销毁，释放线性表L所占用的内存空间</li></ul></li></ul><h3 id="顺序表示" tabindex="-1"><a class="header-anchor" href="#顺序表示" aria-hidden="true">#</a> 顺序表示</h3><ul><li><p>基础概念</p><ul><li><p>定义</p><ul><li>顺序表：顺序存储的线性表</li><li>顺序表中的元素的逻辑顺序与实际的物理位置相同</li><li>线性表中的元素的位序是从1开始的，数组中的元素的下标是从0开始的</li></ul></li><li><p>存储分配</p><ul><li>静态分配：数组的大小和空间都是实现确定好的，一旦存储空间占满就会产生溢出，直接导致程序崩溃</li><li>动态分配：存储数据的空间在程序执行过程中通过动态存储分配语句分配的，即便是数据空间占满，也可以另外开辟一块更大的空间，来替换原来的存储空间</li><li>malloc()函数： 指针型函数，返回的指针指向该分配域的开头的位置。作用是在内存的动态存储区中分配一个长度为size的连续空间</li><li>动态分配不是链式存储，而是属于顺序存储结构，动态分配的物理结构没有改变，依然是随机存取的方式。只是分配的空间大小可以在运行时决定</li></ul></li><li><p>重要特点</p><ul><li>随机访问【重要】</li><li>存储密度高</li><li>逻辑上相邻的元素物理上也相邻</li></ul></li></ul></li><li><p>基本操作</p><ul><li><p>插入元素</p><ul><li><p>在顺序表L的第i（1≤i≤L.length+1）个位置插入新元素，成功返回true,失败返回false</p></li><li><p>时间复杂度</p><ul><li>最好情况：在表尾插入，元素向后移动循环没有执行，时间复杂度O(1);</li><li>最坏情况：在表头插入，元素后移循环执行n次，时间复杂度为O(n);</li><li>平均情况：随机插入，平均次数为：n/2，对应的平均复杂度为O(n);</li></ul></li><li><p>平均时间复杂度为：O(n)</p></li></ul></li><li><p>删除元素</p><ul><li><p>删除顺序表L中第i（1≤i≤L.length+1）个位置的元素。成功则返回true,将被删除的元素用引用变量返回，失败则返回false</p></li><li><p>时间复杂度</p><ul><li>最好情况：删除表尾元素，不需要移动任何元素，时间复杂度为O(1)；</li><li>最坏情况：删除表头元素，需要移动除第一个元素外的所有元素，时间复杂度为O(n)</li><li>平均情况：随机删除，平均需要(n-1)/2，对应的时间复杂度为O(n)</li></ul></li><li><p>平均时间复杂度为O(n)</p></li></ul></li><li><p>按值查找（顺序查找）</p><ul><li><p>在顺序表L中查找第一个元素值等于e的元素查找成功返回该元素位序（不是角标），查找失败返回0</p></li><li><p>位序（个人理解）：元素在线性表中的位置序号，角标为i（角标从0开始）,对应的位序为i+1（位序从1开始）。当返回为0时，则直接代表没有命中</p></li><li><p>时间复杂度</p><ul><li>最好情况：查找的元素在表头，只需要比较一次，循环成本最小，时间复杂度为O(1);</li><li>最坏情况：查找的元素在表尾或者不存在，需要完整遍历，比较n次，时间复杂度为O(n);</li><li>平均情况：随机查找表上的第i个（1≤i≤L.length）元素,平均次数为(n+1)/2,对应时间复杂度为O(n)</li></ul></li><li><p>平均时间复杂度为O(n)</p></li></ul></li></ul></li></ul><h3 id="链式表示" tabindex="-1"><a class="header-anchor" href="#链式表示" aria-hidden="true">#</a> 链式表示</h3><ul><li><p>基础理解</p><ul><li>链式存储线性表时，不需要使用连续的存储单元，不要求逻辑上相邻的两个元素在物理位置上也相邻</li><li>链式存储线性表时，对线性表的插入、删除元素是不需要移动元素的，只是需要修改指针</li><li>理解“链”的含义，链条---&gt;捆绑、指向------&gt;指针</li></ul></li><li><p>单链表</p><ul><li><p>定义：线性表的链式存储称作单链表，通过一组任意的存储单元来存储线性表中的数据元素。</p></li><li><p>每个链表结点（node）除了存放元素自身的信息外，还需要存放一个指向其后继结点的指针。通过指针建立起链表元素之间的线性关系</p></li><li><p>单链表可以解决顺序表需要大量连续存储空间的缺点，但是单链表在数据域的基础上附加了指针域，存在浪费存储空间的缺点</p></li><li><p>单链表的元素是离散地分布在存储空间中的，不能直接找到表中特定的结点，需要从头开始遍历、一次查找【单链表是非随机存取的存储结构】</p></li><li><p>头结点相关</p><ul><li><p>定义：为了操作上的方便，在单链表第一个结点之前附加一个结点，叫做头结点。</p></li><li><p>基本特点</p><ul><li>不论单链表是否带头结点【可选】，头指针始终指向链表的第一个结点</li><li>头结点的指针域指向线性表的第一个元素结点</li><li>头结点的数据域可以不存任何信息、也可以记录表长等基础信息</li><li>头结点是带头结点的链表中的第一个结点</li></ul></li><li><p>优点</p><ul><li>因为开始结点的位置被存放在头结点的指针域中，所以在链表的第一个位置上的操作和在表的其他位置上的操作一致，不需要进行特殊处理</li><li>无论链表是否为空，头指针始终是指向头结点的头结点的非空指针</li><li>头结点的引入，很好的统一了空表和非空表的操作，有效避免头指针空指针异常问题</li></ul></li></ul></li><li><p>基本操作</p><ul><li><p>链表创建</p><ul><li><p>头插法</p><ul><li>定义：从空表开始，生成新的结点，将读取的数据存放在新结点的数据域中，将新结点插入到当前链表的表头【头结点之后】</li><li>读入数据的顺序与生成的链表中的元素顺序是相反的</li><li>每个结点插入的时间复杂度为O(1),单链表长度为n时，头插法的时间复杂度为O(n)</li></ul></li><li><p>尾插法</p><ul><li>定义：新结点插入到当前链表的表尾上，必须增加一个尾指针r,始终指向当前链表的尾结点</li><li>读入数据的顺序与生成的链表中的元素顺序完全一致</li><li>每个结点插入的时间复杂度为O(1),单链表长度为n时，尾巴插法的时间复杂度为O(n)</li><li>相比头插法附设了一个指向表尾结点的指针，但时间复杂度与头插法相同</li></ul></li></ul></li><li><p>按序号查找</p><ul><li>定义：在单链表中从第一个结点出发，顺指针next域逐个往下搜索、遍历，直到找出第i个结点为止，否则返回最后一个结点指针域NULL</li><li>时间复杂度为：O(n)</li></ul></li><li><p>按值查找</p><ul><li>定义：从单链表的第一个结点开始，从前往后依次比较表中个结点数据域的值，等于给定值e，则返回该结点的指针；若整个单链表【遍历完】中没有数据域值为e的结点，则返回NULL；</li><li>时间复杂度为：O(n)</li></ul></li><li><p>插入结点</p><ul><li><p>定义：单链表中，将值为x的新结点插入到单链表的第i个位置上</p></li><li><p>基本步骤</p><ul><li>第一步： 检查插入位置的合法性；</li><li>第二步： 找到待插入位置的前驱结点，即第（i-1）个结点；</li><li>第三部： 在前驱结点后插入新结点；</li><li>过程不能更换，避免后继指针不存在的问题</li></ul></li><li><p>时间复杂度</p><ul><li>插入结点的时间复杂度集中在查找第(i-1)个元素，时间复杂度为O(n)</li><li>如果在给定结点的后面插入新结点，只需要执行p-&gt;next=s操作，时间复杂度为O(1)</li></ul></li><li><p>前插操作：在某结点的前面插入一个新的结点</p></li><li><p>后插操作：在某结点的后面插入一个新的结点，单链表插入算法中，通常采用后插操作的</p></li><li><p>对结点的前插操作都可以转化为后插操作，前提：需要从单链表的头结点开始顺序查找到其前驱结点；时间复杂度为O(n)。</p></li></ul></li><li><p>删除结点</p><ul><li><p>定义：将单链表L的第i个结点元素删除；</p></li><li><p>基本步骤</p><ul><li>第一步： 先检查删除位置的合法性；</li><li>第二步： 查找表中的第（i-1）个结点，即被删结点的前驱结点；</li><li>第三步： 移动指针，删除结点元素；</li></ul></li><li><p>和插入算法一样，时间都消耗在查询前驱结点上，时间复杂度为：O(n)</p></li><li><p>利用p结点的后继结点将p结点删除【经典思路】</p><ul><li>第一步：申请结点q，使其只想p结点的后继结点；</li><li>第二步：将p结点的数据域值换成其后继结点的数据域；【注意，交换没什么意义，最终p的后继结点会删除、释放】</li><li>第三步：p的指针域指向q的指针域，q结点从链中“断开”</li><li>第四步：释放q的内存空间</li><li>相比按值查找前驱结点来删除给定的结点p，利用后继结点来删除的时间复杂度更小，为：O(1)</li></ul></li></ul></li><li><p>计算表长(遍历)</p><ul><li><p>定义：计算单链表中数据结点（不含头结点）的个数</p></li><li><p>算法思路：从第一个结点开始顺序依次访问表中的每一个结点，为此需要设置一个<code>计数器变量</code>，每访问一个结点，计算器加1，直到访问到空结点为止。</p></li><li><p>时间复杂度：O(n)</p></li><li><p>判空条件</p><ul><li>不带头结点的单链表L为空,判定条件是L=NULL。</li><li>带头结点的单链表L为空，判空条件：L-&gt;next=NULL</li></ul></li></ul></li></ul></li></ul></li><li><p>双链表</p><ul><li><p>定义：在单链表的结点中增加了一个指向结点前驱的<code>prior</code>指针，由prior指针域、data数据域、next指针域三部分组成。</p></li><li><p>基本特点</p><ul><li>双链表仅仅在单链表的结点中增加了一个指向结点前驱的prior指针</li><li>按值查找、按序号查找在单链表和双链表上的操作是相同的</li><li>和单链表不同，插入、删除操作除了修改next指针域，双链表还需要修改prior指针域，确保不断<code>链</code>【重要】</li></ul></li><li><p>基本操作</p><ul><li><p>插入结点</p><ul><li>第一步：s-&gt;next=p-&gt;next</li><li>第二步：p-&gt;next-prior=s</li><li>第三步：s-&gt;prior=p</li><li>第四步：p-&gt;next=s</li><li>时间复杂度：O(1)</li><li>注意：结点p和s的前驱、后继指针要关联清楚，第一二步必须在第四步之前完成【重要】</li></ul></li><li><p>删除结点</p><ul><li>第一步：p-&gt;next=q-&gt;next</li><li>第二步：q-&gt;next-&gt;prior=p</li><li>第三步：free(q) 释放结点内存空间</li><li>时间复杂度：O(1)</li><li>注意：删除双链表结点p的后继结点的第一二步，顺序可换，及时释放内存空间【重要】</li></ul></li></ul></li></ul></li><li><p>循环链表</p><ul><li><p>循环单链表</p><ul><li><p>定义：在单链表的基础上，将最后一个结点（尾结点）的指针由<code>NULL</code>改为指向<code>头结点</code>，形成<code>环</code>。【单链表-----&gt;循环单链表】</p></li><li><p>判断条件</p><ul><li>不是判断头结点的指针是否为空，而是需要判断是否等于头指针</li><li>表为空时，头结点的next指针域其实是指向自己</li><li>结点的next指针指向自己，也就能判断表为空</li></ul></li><li><p>基本特点</p><ul><li>在循环单链表中，尾结点*p的next指针域指向链表L（即：头结点），形成了<code>闭环</code>,不存在指针域为<code>NULL</code>的结点</li><li>由于循环单链表是个<code>环</code>,在任何位置上的插入、删除操作都是等价的，不需要去判断是否是表尾</li><li>单链表只能从头结点（表头结点）开始往后顺序遍历整个表，循环单链表可以从表中任意位置开始遍历整个链表，结点是等价的</li><li>循环单链表可以抽象为时钟，形成的<code>环</code>是有顺序的</li><li>频繁的<code>表头</code>和<code>表尾</code>操作，可以对循环单链表设置<code>尾指针</code>，而不设置<code>头指针</code>，明确尾指针r后，头指针即为：<code>r-&gt;next</code> ，减少头指针到尾指针间的遍历，时间复杂度:O(n)----&gt;O(1)</li></ul></li></ul></li><li><p>循环双链表</p><ul><li><p>定义：在双链表的基础上，将尾结点的next指针指向头结点，将头结点的prior指针指向尾结点。【双链表-----&gt;循环双链表】</p></li><li><p>判空条件</p><ul><li><p>循环双链表为空时，头结点*p的prior指针和next指针都指向L</p></li><li><p>同时满足</p><ul><li>p-&gt;prior=L</li><li>p-&gt;next=L</li></ul></li></ul></li><li><p>基本特点：从双向链表中的任意一个结点开始，都可以很方便地访问它的<code>前驱结点</code>和<code>后继结点</code></p></li></ul></li></ul></li><li><p>静态链表</p><ul><li><p>定义：借助数组来描述线性表的链式存储结构，结点元素同样存在数据域<code>data</code>和指针域<code>next</code></p></li><li><p>需要注意</p><ul><li>和普通的链表的指针域不同的是，静态链表的指针是结点元素的相对地址(数组下标)，也称为<code>游标</code>，建议结合高级语言中数组的概念来理解；</li><li>与顺序表一样，虽然静态链表属于链表，但是存储时需要预先分配一块连续的内存空间</li><li>静态链表是通过<code>数组游标</code>来访问下一个结点元素</li></ul></li><li><p>特点</p><ul><li>静态链表以<code>next=-1</code>作为结束的标志【尾结点】</li><li>和动态链表相同，插入、删除操作不需要移动元素，只需要修改指针；</li><li>总体来说，静态链表没有单链表使用方便，需要将整个链表存储在一块连续的内存空间中，内部的存储可以分散，通过指针构成<code>链</code>的关系</li></ul></li></ul></li><li><p>零碎知识补充</p><ul><li><p>无论是链表的插入还是删除操作，必须保证不断链【重要】</p></li><li><p>顺序存储结构可以随机存取也能顺序存取，链式结构只能进行顺序存取</p></li><li><p>顺序存储方式同样适合图和树的存储，例如：满二叉树的顺序存储</p></li><li><p>队列需要在表头删除元素，在表尾插入元素【先进先出】，采用带尾指针的循环单链表比较方便</p></li><li><p>静态链表中的指针称为<code>游标</code>，指示下一个元素在数组中的<code>下标</code></p></li><li><p>静态链表用数组表示，需要预先分配较大的连续空间，同时具有一般链表的特点（插入、删除元素不需要移动元素）</p></li><li><p>单链表设置头结点的</p><ul><li><p>目的：方便运算</p></li><li><p>好处</p><ul><li>有头结点后，插入、删除数据元素的算法统一起来了，不需要判断是否在第一个元素之前插入或者删除第一个元素了</li><li>不论链表是否为空，头指针是指向头结点的<code>非空指针</code>，链表的头指针不变，因此空链表和非空链表的处理也就统一起来了。</li></ul></li></ul></li></ul></li></ul><h3 id="顺序表和链表的比较" tabindex="-1"><a class="header-anchor" href="#顺序表和链表的比较" aria-hidden="true">#</a> 顺序表和链表的比较</h3><ul><li><p>存取方式</p><ul><li>顺序表支持顺序存取和随机存取</li><li>链表只能从表头顺序存取元素，支持顺序存取</li></ul></li><li><p>逻辑结构与物理结构</p><ul><li>顺序存储时，逻辑上相邻的元素，对应的物理存储位置也相邻【一定性】</li><li>链式存储时，逻辑上相邻的元素，对应的物理存储位置不一定相邻【可以相邻，也可以不相邻】</li><li>链式存储的逻辑关系通过指针链接表示</li></ul></li><li><p>时间复杂度</p><ul><li><p>按值查找</p><ul><li>顺序表无序的情况下，顺序表和链表的时间复杂度均为O(n)；</li><li>顺序表有序的情况下，顺序表的时间复杂度为O(log2n),链表为O(n)；</li></ul></li><li><p>按序号查找</p><ul><li>顺序表支持随机访问，时间复杂度为O(1)；</li><li>顺序表不支持随机访问，时间复杂度为O(n)；</li></ul></li><li><p>插入、删除</p><ul><li>顺序表平均需要移动半个表长的元素；</li><li>链表只需要修改相应结点的指针域，不需要移动元素；</li><li>链表结点除了数据域，还有指针域，在存储空间上比顺序存储需要更大的存储空间，付出更大的存储代价，存储密度不够大</li></ul></li></ul></li><li><p>空间分配</p><ul><li><p>顺序存储</p><ul><li><p>静态分配</p><ul><li>需要预先分配足够大的存储空间</li><li>空间装满后不能扩充，存储新元素将出现<code>内存溢出</code></li><li>存储空间过大，顺序表后部闲置空间过多，造成<code>内部碎片</code></li><li>存储空间过小，会造成<code>内存溢出</code></li></ul></li><li><p>动态分配</p><ul><li>能够扩充存储空间</li><li>需要移动大量元素，操作效率降低</li><li>内存中没有更大块的连续存储空间，将会导致空间分配失败；</li></ul></li></ul></li><li><p>链式存储</p><ul><li>结点空间只在需要的时候申请分配</li><li>只要内存由空间就可以分配，操作灵活、高效</li></ul></li></ul></li></ul><h3 id="存储结构选取" tabindex="-1"><a class="header-anchor" href="#存储结构选取" aria-hidden="true">#</a> 存储结构选取</h3><ul><li><p>基于存储的考虑</p><ul><li>对线性表的长度和存储规模难以估计时，不宜采用顺序表存储</li><li>链表不用事先估计存储规模，但存储密度较低</li><li>链式存储结构的存储密度小于1，不要求连续的存储空间</li></ul></li><li><p>基于运算的考虑</p><ul><li><p>随机存取</p><ul><li>顺序表支持随机存取，按序号查找顺序表的时间复杂度为O(1)，相对较好</li><li>链表不支持随机存取，按序号查找链表的时间复杂度为O(n)</li></ul></li><li><p>插入、删除操作</p><ul><li>顺序表的插入、删除操作，平均需要移动表中一半的元素，当表的数据量较大时，这种情况需要重点考虑的</li><li>链表的插入、删除操作，也是需要找插入位置（前驱结点、后继结点），主要的操作还是比较操作，相对较好</li></ul></li></ul></li><li><p>基于环境的考虑</p><ul><li>顺序表容易实现，任何高级语言中都有数组类型</li><li>链表操作是基于指针的，指针移动，相对复杂</li></ul></li><li><p>综合结论</p><ul><li>通常比较稳定的线性表选择顺序存储</li><li>频繁进行插入、删除操作的线性表，应该选择链式存储，动态性较强</li></ul></li></ul><h2 id="栈和队列" tabindex="-1"><a class="header-anchor" href="#栈和队列" aria-hidden="true">#</a> 栈和队列</h2><h3 id="栈【后进先出】" tabindex="-1"><a class="header-anchor" href="#栈【后进先出】" aria-hidden="true">#</a> 栈【后进先出】</h3><ul><li><p>基础概念</p><ul><li><p>定义： 只允许在一端进行插入或者删除操作的线性表。</p><ul><li>后进先出</li><li>明确栈是一种线性表</li><li>限定栈只能在某一端进行插入或者删除操作</li></ul></li><li><p>栈顶：线性表允许进行插入和删除的一端</p></li><li><p>栈底：不允许进行插入和删除的另外一端，是固定的</p></li><li><p>空栈：不含任何元素的空表，也叫栈空</p></li></ul></li><li><p>基本操作</p><ul><li>InitStack(&amp;S): 初始化一个空栈S，栈顶指针初始化为-1</li><li>StackEmpty(S): 判断一个栈是否为空，如果栈空则返回true,否则返回false</li><li>Push(&amp;S,x): 进栈，若栈未满，x进栈操作，插入到栈内成为新的栈顶元素</li><li>Pop(&amp;S,&amp;x): 出栈，若栈非空，出栈操作，弹出栈顶元素，用指针x进行返回</li><li>GetTop(S,&amp;x): 读栈顶元素，若栈S非空，用x返回栈顶元素</li><li>ClearStack(&amp;S): 销毁栈，释放栈S占用的存储空间</li></ul></li><li><p>顺序存储结构</p><ul><li><p>顺序栈</p><ul><li><p>定义：栈的顺序存储，利用一组地址连续的存储单元存放自栈底到栈顶的所有元素，同时<strong>附加一个用来指向当前栈顶位置的指针</strong></p></li><li><p>顺序栈S【重要，栈顶指针初始化为-1】</p><ul><li><p>栈顶指针S.top</p><ul><li>初始时，S.top=-1</li><li>栈顶元素:S.data[S.top]</li></ul></li><li><p>进栈操作：栈不满时，栈顶+1，再进栈</p></li><li><p>出栈操作：栈非空时，取栈顶元素，栈顶-1</p></li><li><p>栈满条件：S.top=MaxSize-1</p></li><li><p>栈空条件：S.top=-1</p></li><li><p>栈长：S.top+1</p></li><li><p>当对栈的最大使用空间估计不足时，容易出现栈上溢(外溢)，需要主动向用户报告反馈，避免出现错误；</p></li></ul></li><li><p>栈顶指针初始化为0【更多是为-1】</p><ul><li>入栈： <code>S.data[S.top++]=x</code></li><li>出栈： <code>x=S.data[--S.top]</code></li><li>同时， 栈空、栈满条件也会有变化</li></ul></li><li><p>基本运算</p><ul><li><code>InitStack(&amp;S)</code>: 初始化一个空栈<code>S</code>,栈顶指针初始化为-1</li><li><code>StackEmpty(S)</code>: 判断一个栈是否为空，即：栈顶指针是否为-1，如果栈空则返回<code>true</code>,否则返回<code>false</code></li><li><code>Push(&amp;S,x)</code>: 进栈，若栈未满，<code>x</code>进栈操作，插入到栈内成为<code>新的栈顶元素</code>。</li><li><code>Pop(&amp;S,&amp;x)</code>: 出栈，若栈非空，出栈操作，<strong>弹出栈顶元素</strong>，用指针<code>x</code>进行返回。</li><li><code>GetTop(S,&amp;x)</code>: 读（获取）栈顶元素，若栈<code>S</code>非空，用x返回栈顶元素。</li></ul></li></ul></li><li><p>共享栈</p><ul><li><p>定义：利用栈底位置相对不变的特性，可以让两个顺序栈共享一个<code>一维存储空间</code>，将两个栈的栈底分别设置在共享空间的两端，两个栈顶则向共享空间的中间延伸</p></li><li><p>基础概念</p><ul><li>两个栈（0、1号顺序栈）的栈顶指针都指向栈顶元素</li><li>0号栈栈顶指针<code>top=-1</code>时，0号栈为空</li><li>1号栈栈顶指针<code>top=MaxSize</code>时，1号栈为空</li><li>当且仅当两个栈的栈顶指针相邻(<code>top1-top0=1</code>),可以判断共享栈栈满</li></ul></li><li><p>进栈【先移动指针，后赋值】</p><ul><li>当0号栈进栈时，0号栈栈顶指针top0<code>先加1后赋值</code></li><li>当1号栈进栈时，0号栈栈顶指针top1<code>先减1后赋值</code></li></ul></li><li><p>出栈【先赋值，后移动指针】</p><ul><li>当0号栈进栈时，0号栈栈顶指针top0<code>先赋值后减1</code></li><li>当1号栈进栈时，0号栈栈顶指针top1<code>先赋值后加1</code></li></ul></li><li><p>重要特性</p><ul><li>共享栈能够更有效的利用存储空间，两个栈空间进行相互调节</li><li>只有当这个存储空间（即：共享空间）被占满时才会发生上溢</li><li>共享栈对存取效率没有什么影响，存取数据的时间复杂度都为O(1)，在栈顶操作。</li></ul></li></ul></li></ul></li><li><p>链式存储结构</p><ul><li><p>基本概念</p><ul><li><code>链栈</code>： 采用链式存储的栈</li><li><code>栈满</code>：对于链栈来说，是基于链式存储的，基本不存在栈满的情况，除非内存已经没有使用空间了</li><li><code>栈空</code>：对于空栈来说，链表原来的定义是头指针指向空，那么链栈的空其实就是<code>top＝NULL</code>,链栈元素总数为0</li><li>通常对于链栈来说，是不需要头结点的，当然也存在带头结点的链栈</li></ul></li><li><p>基础操作【基于单链表】</p><ul><li><p>入栈</p><ul><li>如果链栈不存在，则栈满，入栈操作失败，返回false;</li><li>如果链栈存在，进行单链表的结点插入操作，移动指针，结点元素赋值，再将结点压入链栈中，移动链栈栈顶指针，最后链栈元素总数+1，返回true</li></ul></li><li><p>出栈</p><ul><li>如果链栈不存在，或者为空栈，则无法进行出栈操作，返回false</li><li>如果链栈满足出栈条件，则通过栈顶指针获取到链栈栈底结点，将其数据域赋值给变量e，移动栈顶指针指向待出栈元素的后继结点，同时释放待出栈元素的内存空间，链栈元素总数-1 ，出栈成功，返回true.</li></ul></li><li><p>基于单链表的链栈入栈、出栈操作，时间复杂度都为O(1）【重要】</p></li></ul></li><li><p>优点</p><ul><li>便于多个栈共享存储空间</li><li>不存在栈满上溢的情况，避免程序因溢出导致出错</li><li>有效的提高存取效率</li></ul></li></ul></li></ul><h3 id="队列【先进先出】" tabindex="-1"><a class="header-anchor" href="#队列【先进先出】" aria-hidden="true">#</a> 队列【先进先出】</h3><ul><li><p>基本概念</p><ul><li>队列：和栈一样，是一种操作受限制的线性表,只允许在表的一端进行插入，在表的另外一端进行删除，简称为<code>队</code>，常记作：<code>Queue</code></li><li>队头：允许进行删除操作的一端，也叫做<code>队首</code>，常记作：<code>Front</code></li><li>队尾：允许进行插入操作的一端，常记作：<code>Rear</code></li><li>空队列：不含任何元素的空表，注意这个表是指<code>线性表</code></li><li>入队： 向队列中插入元素，也叫做<code>进队</code></li><li>出队： 删除队列元素，也叫做<code>离队</code></li></ul></li><li><p>基础操作</p><ul><li>InitQueue(&amp;Q)： 初始化一个队列，构造空队列Q</li><li><code>QueueEmpty(Q)</code>： 判断队列是否为空，队空返回true,否则返回false</li><li>EnEmpty(&amp;Q,x)： 入队，如果队列Q未满，将x入队，成为新的队尾元素</li><li>DeEmpty(&amp;Q,&amp;x)： 出队，如果队列Q非空，删除队头元素，复制给x返回</li><li>GetHead(Q,&amp;x)： 读取队头元素，如果队列Q非空，则将队头元素赋值给x</li></ul></li><li><p>顺序存储</p><ul><li><p>顺序队列</p><ul><li><p>队列的顺序实现是指分配一块连续的存储单元用来存放队列中的元素，并且附加两个指针</p><ul><li>front指针： 指向队头元素的位置</li><li>rear指针： 指向队尾元素的位置</li></ul></li><li><p>初始状态（队空条件）：Q.front===Q.rear===0</p></li><li><p>入队操作：队不满时，先赋值给队尾元素，再移动队尾指针+1</p></li><li><p>出队操作： 队不空时，先取队头元素值，再移动队头指针+1</p></li><li><p>Q.front===Q.rear===0,那能用Q.rear==MaxSize来表示队满嘛？【不行】</p></li></ul></li><li><p>循环队列</p><ul><li><p>把顺序队列臆想为一个环状的空间，将存储队列元素的表从逻辑上看做为一个环</p></li><li><p>初始时：Q.front=Q.rear=0</p></li><li><p>队首指针进1： Q.front=(Q.front+1)%MaxSize</p></li><li><p>队尾指针进1： Q.rear=(Q.rear+1)%MaxSize</p></li><li><p>队列长度： (Q.rear+MaxSize-Q.front)%MaxSize</p></li><li><p>除法取余运算（%）【解决顺序队列“上溢出”】问题</p></li><li><p>如何区别队空还是队满？</p><ul><li><p>方案一：牺牲一个单元来区分队空和队满</p><ul><li>前提：队头指针在队尾指针在队尾指针的下一个位置作为队满标志【重要】</li><li>队满条件：(Q.rear+1)%MaxSize==Q.front</li><li>队空条件：Q.front==Q.rear</li><li>队列中元素个数：(Q.rear+MaxSize-Q.front)%MaxSize</li></ul></li><li><p>方案二：类型中增设表示元素个数的数据成员</p><ul><li>直接和MaxSize去比较</li><li>队空条件： Q.count=0</li><li>队满条件： Q.count=MaxSize</li><li>【注意】不论是队空还是队满，对会存在Q.front=Q.rear,这个可以通过前面方案一解决</li></ul></li><li><p>方案三：类型中增设tag数据成员标记</p><ul><li><p>通过添加tag标记的方式，区分队空还是队满</p></li><li><p>tag==0的情况下，如果因为删除导致Q.front==Q.rear，则队空；</p></li><li><p>tag==1的情况下，如果因为插入导致Q.front==Q.rear，则队满；</p></li><li><p>tag的主要作用</p><ul><li>在有元素入队的时候，设置tag=1</li><li>在有元素出队的时候，设置tag=0</li></ul></li></ul></li></ul></li></ul></li></ul></li><li><p>链式存储</p><ul><li><p>链队列</p><ul><li><p><code>链队列</code>：和顺序队列一样，基于队列的链式表示叫做<code>链队列</code>，实际上为：<strong>一个同时带有队头指针和队尾指针的单链表</strong></p><ul><li>头指针指向队头结点</li><li>尾指针指向队尾结点（单链表的最后一个结点）</li></ul></li><li><p>不带头结点链式队列</p><ul><li>队空： linkQueue.front==NULL且linkQueue.rear==NULL</li><li>出队： 先判断队列是否为空，非空队列则取出队头元素，从链表中闪出去，队头指针Q.front指向下一个结点，如果出队的结此为尾结点，出队后队空，需要将Q.front和Q.rear都置为NULL</li><li>入队： 建立一个新的结点，将新的结点插入到链表的尾部，修改队尾指针Q.rear指向新插入的结点。如果原队列为空，需要将队首指针也指向该结点</li><li>【入队、出队操作，都需要考虑队空的情况下的特殊处理，不带头结点的队列导致队空队首和队尾指针都为NULL，麻烦】</li></ul></li><li><p>带头结点的链式队列</p><ul><li>【复杂的入队、出队操作就统一起来】</li><li>队空：Q.front==Q.rear,都指向头结点，一般数据域可以为空</li><li>出队：判断队列是否为空，队列非空则在队首移动指针，将队首指针指向下一个元素。如果队列中就一个元素，则出队后将成为空队，Q.rear==Q.front,最后释放元素内存空间。</li><li>入队：将元素插入队尾，移动队尾指针，即便为空队列入队，由于队列带有头结点，此时就很好的避免操作队首指针了。</li><li>子主题 5</li></ul></li><li><p>特别注意</p><ul><li>用单链表表示的链式队列非常适合频繁出队、入队、元素变化大的场景</li><li>不存在队满情况，也不会出现溢出情况；</li><li>链式队列不会出现存储分配不合理、“溢出”的情况，内存动态分配</li></ul></li><li><p>基本操作【带头结点】</p><ul><li>队列初始化</li><li>判断队空：Q.front==Q.rear</li><li>入队【重要】</li><li>出队【重要】</li></ul></li></ul></li><li><p>双端队列</p><ul><li><p>允许在两端都可以进行入队和出队操作的队列，元素的逻辑结构仍然是线性结构</p></li><li><p>双端队列的两端分别称为前端和后端，两端都可以入队和出队</p><ul><li>进队：前端进的元素排列在队列中后端进的元素的前面，后端进的元素排列在队列前端进的元素后面;</li><li>出队：无论是前端还是后端出队，先出的的元素排列在后出的元素的前面</li></ul></li><li><p>输入受限的双端队列：允许在一端进行插入和删除操作，但在另外一端只允许进行删除的双端队列</p></li><li><p>输出受限的双端队列：允许在一端进行插入和删除曹组，但在另外一端只允许进行插入的双端队列</p></li><li><p>如果限定双端队列从某个断点插入的元素只能从该端点删除，那么此时的双端队列就演变为两个栈底相邻的栈</p></li></ul></li><li><p>补充</p><ul><li>最适合用来链队的链表是：带队首指针和队尾指针的非循环单链表</li><li>栈和队列的逻辑结构都是线性表，存储结构可能是顺序的（顺序栈、顺序队列），也可能是链式的（链栈、链队）</li><li>不论是顺序存储还是链式存储，栈和队列都只能进行顺序存取（本质是线性表）。数组是可以做到随机存取（本质是顺序表）</li><li>队列先进先出的特性：先进队列的元素先出队列，后进队列的元素后出队列</li></ul></li></ul></li></ul><h3 id="应用" tabindex="-1"><a class="header-anchor" href="#应用" aria-hidden="true">#</a> 应用</h3><ul><li><p>【栈】括号匹配</p></li><li><p>【栈】表达式求值</p></li><li><p>【栈】递归算法</p><ul><li><p>定义： 如果在一个函数、过程或数据结构的定义中又应用了自身，那么这个函数、过程或者数据结构称为递归定义的，简称递归。</p></li><li><p>递归通常把一个大型的复杂问题，层层转化为一个与原问题相似的规模较小的问题来求解</p></li><li><p>斐波拉切数列算法优化</p><ul><li>使用非递归实现</li><li>使用空间换效率，例如：数组</li><li>使用缓存，存放数据</li></ul></li><li><p>必须注意递归模型不能是循环定义， 需要满足两个条件</p><ul><li>递归表达式（递归体）</li><li>边界条件（递归出口），即：算法结束条件</li></ul></li><li><p>特点</p><ul><li>很大程度上减少了程序的代码量</li><li>算法效率不高【重要特点】</li><li>调用次数过多容易造成栈溢出</li></ul></li></ul></li><li><p>【队列】层次遍历</p></li><li><p>【队列】计算机系统</p><ul><li>解决主机和外部设备之间速度不匹配的问题</li><li>解决由多用户引起的资源竞争问题</li></ul></li></ul><h3 id="特殊矩阵的压缩存储" tabindex="-1"><a class="header-anchor" href="#特殊矩阵的压缩存储" aria-hidden="true">#</a> 特殊矩阵的压缩存储</h3><ul><li><p>在<code>计算机图形学</code>、<code>工程计算</code>中占有举足轻重的地位。</p></li><li><p>数组定义：由n(n≥1)个相同类型的数据元素构成的有限序列。</p></li><li><p>重要概念</p><ul><li>【压缩存储】多个值相同的元素只分配一个存储空间，对零元素不分配存储空间----&gt;节省存储空间。</li><li>【特殊矩阵】具有很多相同矩阵元素或零元素，并且这些相同矩阵元素或零元素的分布有一定规律性的矩阵。</li><li>【稀疏矩阵】矩阵元素个数s相对于矩阵中非零元素的个数t来说非常多、差距非常大，即<code>s&gt;&gt;t的矩阵</code>可以叫<code>稀疏矩阵</code></li></ul></li><li><p>常见的特殊矩阵</p><ul><li>对称矩阵</li><li>上、下三角矩阵</li><li>对角矩阵（带状矩阵）</li><li>......</li></ul></li><li><p>注意</p><ul><li>常规方法来存储稀疏矩阵，会想当浪费存储空间，所以稀疏矩阵只需要存储非零元素</li><li>通常非零元素的分布是没有规律的，除了存储非零元素外，还需要存储元素所在位置的行和列</li><li>寻相互存储三元组 <code>&lt;行标，列表，值&gt;</code></li><li>三元组的结点存储了行标(row)、列表(col)、值(value)三种信息，是主要用来存储稀疏矩阵的一种数据结构</li></ul></li><li><p>数组和线性表的关系</p><ul><li>数组是线性表的推广</li><li>数组一旦被定义，维数和维界就不再改变</li><li>除了结构的初始化和销毁外，数组只会有存取元素和修改元素的操作</li></ul></li><li><p>数组的存储结构</p><ul><li>按行优先</li><li>按列优先</li></ul></li></ul><h2 id="树与二叉树" tabindex="-1"><a class="header-anchor" href="#树与二叉树" aria-hidden="true">#</a> 树与二叉树</h2><h3 id="树" tabindex="-1"><a class="header-anchor" href="#树" aria-hidden="true">#</a> 树</h3><ul><li><p>定义</p></li><li><p>术语</p><ul><li><p>结点</p><ul><li>祖先结点</li><li>父子结点</li><li>兄弟结点</li><li>孩子结点</li><li>子孙结点</li><li>分支结点</li><li>叶子结点（终端结点）</li></ul></li><li><p>度</p><ul><li>结点的度</li><li>树的度</li></ul></li><li><p>结点的深度、高度、层次</p></li><li><p>有序树和无序树</p></li><li><p>路径和路径长度</p></li><li><p>森林</p></li></ul></li><li><p>性质</p></li></ul><h3 id="二叉树" tabindex="-1"><a class="header-anchor" href="#二叉树" aria-hidden="true">#</a> 二叉树</h3><ul><li>定义和特性</li><li>存储结构</li><li>二叉树遍历</li><li>线索二叉树</li></ul><h3 id="树和森林" tabindex="-1"><a class="header-anchor" href="#树和森林" aria-hidden="true">#</a> 树和森林</h3><ul><li>存储结构</li><li>树、森林与二叉树转换</li><li>遍历</li><li>并查集应用</li></ul><h3 id="应用-1" tabindex="-1"><a class="header-anchor" href="#应用-1" aria-hidden="true">#</a> 应用</h3><ul><li>二叉排序树</li><li>平衡二叉树</li><li>哈夫曼树</li><li>哈夫曼编码</li></ul><h2 id="图论" tabindex="-1"><a class="header-anchor" href="#图论" aria-hidden="true">#</a> 图论</h2><h3 id="定义" tabindex="-1"><a class="header-anchor" href="#定义" aria-hidden="true">#</a> 定义</h3><h3 id="基本操作" tabindex="-1"><a class="header-anchor" href="#基本操作" aria-hidden="true">#</a> 基本操作</h3><ul><li>Adjacent(G,x,y)</li><li>Neighbors(G,x)</li><li>InsertVertex(G,x)</li><li>DeleteVertex(G,x)</li><li>AddEdge(G,x,y)</li><li>RemoveEdge(G,x,y)</li><li>FirstNeighbor(G,x)</li><li>NextNeighbor(G,x,y)</li><li>Get_edge_value(G,x,y)</li><li>Set_edge_value(G,x,y,v)</li></ul><h3 id="存储及操作" tabindex="-1"><a class="header-anchor" href="#存储及操作" aria-hidden="true">#</a> 存储及操作</h3><ul><li>邻接矩阵法</li><li>邻接链表法</li><li>十字链表</li><li>邻接多重表</li></ul><h3 id="图的遍历" tabindex="-1"><a class="header-anchor" href="#图的遍历" aria-hidden="true">#</a> 图的遍历</h3><ul><li>广度优先搜索（BFS）</li><li>深度优先搜索（DFS）</li><li>连通性</li></ul><h3 id="图的应用" tabindex="-1"><a class="header-anchor" href="#图的应用" aria-hidden="true">#</a> 图的应用</h3><ul><li>最小生成树（MST）</li><li>最短路径</li><li>拓扑排序</li><li>关键路劲</li></ul><h2 id="查找" tabindex="-1"><a class="header-anchor" href="#查找" aria-hidden="true">#</a> 查找</h2><h3 id="基本概念-1" tabindex="-1"><a class="header-anchor" href="#基本概念-1" aria-hidden="true">#</a> 基本概念</h3><ul><li><p>查找：在数据集合中寻找满足某种条件的数据元素的过程</p></li><li><p>查找表（查找结构）：用于查找的数据集合</p><ul><li><p>数据元素（记录）的类型相同</p></li><li><p>可以是一个数组或者链表等数据类型</p></li><li><p>常见操作</p><ul><li>查询某个特定元素是否存在</li><li>检索满足条件的特定元素的各种属性</li><li>数据元素插入</li><li>数据元素删除</li></ul></li></ul></li><li><p>静态查找表：不需要动态地修改查找表，与动态查找表对应</p><ul><li>顺序查找</li><li>折半查找</li><li>散列查找</li><li>....</li></ul></li><li><p>动态查找表：需要动态地插入或者删除的查找表</p><ul><li>二叉排序树的查找</li><li>散列查找</li><li>....</li></ul></li><li><p>关键字：数据元素中唯一标识该元素的某个数据项的值</p><ul><li>使用关键字查找，查找结果应该是【唯一的】</li><li>可以类比集合中不重复的key</li><li>是不是想起了数据库的主键的概念？？？？</li></ul></li><li><p>平均查找长度：所有查找过程中进行关键字的比较次数的平均值</p><ul><li>查找长度：一次查找需要比较的关键字次数</li><li>【是衡量查找算法效率的最主要的指标】</li></ul></li></ul><h3 id="顺序查找-线性查找" tabindex="-1"><a class="header-anchor" href="#顺序查找-线性查找" aria-hidden="true">#</a> 顺序查找（线性查找）</h3><ul><li><p>主要用于在线性表中进行查找</p><ul><li>一般的【无序线性表】的顺序查找</li><li>按关键字【有序的顺序表】的顺序查找</li><li>Tips：顺序表是指顺序存储的线性表，前面的有序才强调元素有序，顺序强调的是存储方式</li></ul></li><li><p>基于一般线性表的顺序查找</p><ul><li><p>最直观的查找方式</p></li><li><p>基本思想：从线性表的一端开始，逐个查询条件和关键字进行比对即可</p></li><li><p>【重要】：哨兵的引入，可以避免很多不必要的判断语句，提高程序的效率</p></li><li><p>平均查找长度</p><ul><li><p>查找成功</p><ul><li>第i个元素需要进行(n-i+1)次关键字比较</li><li>概率相等的情况下：(n+1)/2</li></ul></li><li><p>查找失败【没有找到元素】</p><ul><li>各关键字比较次数：(n+1)</li><li>平均查找长度：(n+1)</li></ul></li></ul></li><li><p>综合分析</p><ul><li>【缺点】：n较大时，平均查找长度较大，效率低</li><li>【优点】：对数据元素的存储没有要求，顺序存储和链式存储都可行。对数据元素的有序性也没有要求</li><li>【注意】：线性的链表只能进行顺序查找</li></ul></li><li><p>通常情况下，查找表中记录的查找概率并不相等</p></li></ul></li><li><p>基于有序表的顺序查找</p><ul><li><p>预先已经知道表是按照关键字有序的，基于【二叉判定树】来查找，不用全部遍历-----&gt;【降低顺序查找失败的平均查找长度】</p></li><li><p>平均查找长度</p><ul><li><p>查找成功</p><ul><li>和一般线性表的顺序查找一样</li><li>概率相等的情况下：(n+1)/2</li></ul></li><li><p>查找失败</p><ul><li>到达是失败结点所查找的长度=失败结点父结点所在的层数【建议画画二叉判定树】</li><li>查找概率相等时，平均查找长度:n/2 + n/(n+1)</li></ul></li></ul></li><li><p>【注意】：有序表的顺序查找中的线性表可以是链式存储结构的</p></li></ul></li></ul><h3 id="折半查找-二分查找" tabindex="-1"><a class="header-anchor" href="#折半查找-二分查找" aria-hidden="true">#</a> 折半查找（二分查找）</h3><ul><li><p>【注意】仅仅适用于有序的顺序表</p></li><li><p>基本思想：首先与表中间位置元素的关键字比较，相等则查找成功，不相等则向左|向右继续与该部分中间元素比较......</p></li><li><p>核心思路：左右双指针，互相往中间靠拢，可以用二叉判定树来辅助思考</p></li><li><p>平均查找长度【计算非常重要】</p><ul><li><p>查找成功</p><ul><li>折半查找法查到给定值的比较次数最多不会超过【判定树】的高度</li><li>相等概率下，平均查找长度约等于log2(n+1) -1 ,【建议结合二叉树高度计算来理解】</li></ul></li><li><p>查找失败直接看例题.....</p></li></ul></li><li><p>综合分析</p><ul><li>折半查找的时间复杂度为O(log2n), 平均情况下笔顺序查找O(n)的效率高</li><li>折半查找需要方便地定位查找区域----&gt;存储结构必须具有【随机存取】的特性</li><li>【注意】仅仅适用于有序的顺序表，不适用链式存储结构，要求表按关键字有序排列</li></ul></li></ul><h3 id="分块查找-索引顺序查找" tabindex="-1"><a class="header-anchor" href="#分块查找-索引顺序查找" aria-hidden="true">#</a> 分块查找（索引顺序查找）</h3><ul><li><p>具备顺序查找和折半查找的优点，既有动态结构，又能适用于快速查找</p></li><li><p>是不是有点【希尔排序】和【直接插入排序、折半插入排序】的发展效果？？？？？</p></li><li><p>基本思想：查找表分成若干个子块</p><ul><li>块内元素可以无序，【块之间必须有序】</li><li>前一块的最大关键字永远小于后一块的最小关键字</li><li>【重要】：建立索引表，包含每个分块额最大关键字和第一个元素的地址（起始角标）</li><li>索引表按关键字有序排列</li></ul></li><li><p>查找方式</p><ul><li>索引表：顺序查找或者折半查找</li><li>块内：顺序查找&lt;----- 块内可以无序</li></ul></li><li><p>【直接看书】平均查找长度=索引查找平均长度+块内查找的平均长度</p></li></ul><h3 id="【直接看书-视频-这部分我很迷糊】b树和b-树" tabindex="-1"><a class="header-anchor" href="#【直接看书-视频-这部分我很迷糊】b树和b-树" aria-hidden="true">#</a> 【直接看书|视频，这部分我很迷糊】B树和B+树</h3><ul><li><p>B树（多路平衡查找树）</p><ul><li><p>基础概念</p><ul><li><p>阶：所有结点的孩子结点数的最大值</p></li><li><p>m阶B树（可能为空树）满足</p><ul><li>树中每个结点至多有m棵子树（即至多包含m-1个关键字）</li><li>如果根结点不是终端结点，至少有两棵子树</li><li>所有的叶结点都出现在同一个层次上，不带任何信息</li><li>....</li></ul></li><li><p>B树是所有结点的平衡因子均为0的多路查找树</p></li></ul></li><li><p>基本操作</p><ul><li><p>高度</p><ul><li>B树的大部分操作需要的磁盘存取次数和B树的高度成正比</li><li>B树的高度不包括最后的不带任何信息的叶结点所处的那一层【有的参考书，也包含这部分】</li><li>【重要】如果每个结点重点额关键字个数达到最少，则容纳同样多关键字的B树的高度可以达到最大</li><li>....</li></ul></li><li><p>查找</p><ul><li><p>步骤</p><ul><li>在B树中找结点【磁盘中进行】</li><li>在结点内找关键字【内存中进行】----&gt; 采用【顺序查找法】或【折半查找法】</li><li>【Tips】B树常存储在磁盘上，在磁盘上找到目标节点后，将结点中的信息读入到内存</li></ul></li><li><p>当查找到叶子结点，对应的指针为空指针，即树中没有对应的关键字</p></li></ul></li><li><p>插入</p><ul><li><p>插入操作比查找操作复杂多</p></li><li><p>步骤</p><ul><li><p>定位</p><ul><li>B树查找算法---&gt;最底层中某个非叶结点</li><li>【重要】B树的插入关键字一定是插入到最底层的某个非叶结点内</li></ul></li><li><p>插入</p><ul><li>插入结点关键字个数小于m----&gt; 直接插入</li><li>插入后检查插入结点内关键字个数，【大于m-1必须进行分裂】</li></ul></li><li><p>【直接看书】】注意分裂的方法</p></li></ul></li></ul></li><li><p>删除（删除的关键字在终端结点）</p><ul><li>直接删除关键字</li><li>兄弟够借</li><li>兄弟不够借</li></ul></li></ul></li></ul></li><li><p>B+树的概念</p><ul><li><p>B+树是根据数据库的需要需要的一中B树的变形树</p></li><li><p>m阶的B+树需要满足的条件</p><ul><li><p>每个分支结点最多有m棵子树（子结点）</p></li><li><p>结点的字树个数与关键字相等</p></li><li><p>非叶、根结点至少有两棵子树，其他分支结点至少有m/2(向上取整)棵子树</p></li><li><p>所有叶结点包含全部关键字及指向相应记录的指针</p><ul><li>叶结点按关键字大小排列</li><li>相邻结点按大小顺序相互链接起来</li></ul></li><li><p>【反复理解】所有的分支结点（理解为索引的索引）中仅仅包含它的各个子结点（下一级的索引快）中关键字的最大值和指向其子结点的指针</p></li><li><p>....</p></li></ul></li></ul></li></ul><h3 id="散列-hash-表" tabindex="-1"><a class="header-anchor" href="#散列-hash-表" aria-hidden="true">#</a> 散列（Hash）表</h3><ul><li><p>基本概念</p><ul><li>散列函数：一个把查找表中的关键字映射成该关键字对应的地址（数组下标、索引、内存地址等）的函数</li><li>散列冲突：散列函数把两个或者多个不同关键字映射到同一个地址上，【冲突总是不可避免的】</li><li>同义词：发生散列冲突（碰撞）的不同关键字</li><li>散列表：根据关键字直接访问的数据结构，是关键字和存储地址之间的一种直接映射关系</li><li>理想情况下，散列表中查找时间复杂度为O(1)，与元素个数无关</li><li>基于【比较】的查找算法，查找效率取决于比较的次数</li><li>以上可以结合哈希加密、布隆过滤器等工作中的编程概念去比对学习....</li></ul></li><li><p>散列函数</p><ul><li><p>构造散列函数，需要注意</p><ul><li>散列函数的定义域【必须】要包含全部需要存储的关键字，值域的范围则依赖于散列表的大小或地址范围</li><li>散列函数计算出来的地址应该能【等概率、均匀的】分布在整个存储空间，尽可能减少散列冲突---&gt; 【压测】</li><li>散列函数应该尽量简单，能够在较短时间内就计算出任一关键字对应的散列地址</li></ul></li><li><p>常用散列函数</p><ul><li><p>直接定址法</p><ul><li><p>直接去关键字的某个【线性函数值】为散列函数</p></li><li><p>优点</p><ul><li>计算简单</li><li>【不会产生冲突】</li><li>适合关键字的分布【基本连续】的情况</li></ul></li><li><p>缺点：关键字分布不连续时，空位较多，将造成存储空间的浪费</p></li></ul></li><li><p>除留余数法</p><ul><li>最简单、最常用的散列方法</li><li>关键在于【选择被除数P】，等概率进行映射，尽可能减少冲突的可能性</li></ul></li><li><p>数字分析法</p><ul><li>适用于已知的关键字集合</li><li>如果更换了关键字，就需要重新构造新的散列函数</li></ul></li><li><p>平方取中法</p><ul><li>取关键字的平方值的中间几位来作为散列地址</li><li>适用于关键字的每一位取值都不够均匀或小于散列地址所需要的位数</li></ul></li><li><p>折叠法</p><ul><li>将关键字分割成位数相同的几部分，取这几部分的叠加作为散列地址</li><li>关键字位数很多，每一位上数字分布大致均匀时，可以采用折叠法得到散列地址</li></ul></li><li><p>.....</p></li></ul></li><li><p>不同的情况，不同的散列函数会发挥不同的性能，无法笼统的说那种散列函数最好。散列函数的目标都是为了将产生冲突的可能性尽可能地降低</p></li></ul></li><li><p>处理冲突</p><ul><li><p>【任何设计出来的散列函数都不可能绝对地避免冲突】，必须考虑在发生冲突时如何进行处理</p></li><li><p>处理方法</p><ul><li><p>开放定址法</p><ul><li><p>概念：可以存放新表项的空闲地址，既向它的同义词表项开放，也向它的非同义词表项开放</p></li><li><p>增量取值方法</p><ul><li>线性探测法</li><li>平方探测法</li><li>再散列法（双散列法）</li><li>伪随机序列法</li></ul></li><li><p>注意事项</p><ul><li>不能随便【物理删除】表中已有元素，删除将会截断具有相同散列地址元素的查找地址，牵涉元素广</li><li>删除元素需要【单独做标记】，采用【逻辑删除】</li><li>逻辑删除会导致散列表表面上看上满的，实际上很多位置都是没有被利用的，【需要定期维护，将删除标记的\b元素物理删除】</li></ul></li></ul></li><li><p>拉链（链接）法</p><ul><li>概念：为避免非同义词发生冲突，可以把所有的同义词存储在一个线性链表中【由散列地址唯一标识】</li><li>【重要】适用于经常进行插入和删除的情况</li></ul></li><li><p>拉链法处理冲突时不存在聚集现象，用线性探测法处理冲突时容易产生聚集现象</p></li></ul></li></ul></li><li><p>性能分析</p><ul><li><p>装填因子：一个表的装满程度 =（表中的记录数）/ （散列表的长度）</p></li><li><p>查找效率取决于</p><ul><li>散列函数</li><li>处理冲突的方法</li><li>【重要】装填因子</li></ul></li><li><p>散列表的平均查找长度依赖于【散列表的填装因子】</p></li><li><p>填装因子越大，表示装填的越“满”，发生冲突的可能性就越大</p></li><li><p>散列冲突导致散列表在查找过程中也是需要进行比较的。【查找效率仍然用平均查找长度来度量】</p></li><li><p>冲突的产生概率与装填因子（表中记录数和表长）的大小成正比</p></li></ul></li></ul><h3 id="模式匹配-字符串" tabindex="-1"><a class="header-anchor" href="#模式匹配-字符串" aria-hidden="true">#</a> 模式匹配（字符串）</h3><ul><li><p>简单模式匹配</p><ul><li>概念：第一个字符串（模式串）在第二串（主串）中的位置</li><li>基本过程：从主串指定字符开始（一般第一个）和模式串的第一个字符逐个比较....</li><li>时间复杂度：O(n*m)，n、m分别为主串和模式串的长度</li></ul></li><li><p>【难点，直接看代码理解】KMP算法</p><ul><li><p>【重要】是对简单模式匹配的改造，时间复杂度在O(n+m)的数量集上</p></li><li><p>【建议手动模拟】基本过程</p><ul><li>整个匹配过程，没有进行指针回溯</li><li>每趟比较过程让子串向后滑动到一个合适位置， 让这个位置上的字符和主串中的那个字符比较</li><li>【重要】next数组的求解实际是对某个位置找到最长的公共前缀</li></ul></li></ul></li><li><p>总结比较</p><ul><li>简单模式匹配时间复杂度：O(n*m)</li><li>KMP算法的时间复杂度为O(n+m)</li><li>一般情况下，简单模式匹配的实际执行时间可以近似到O(n+m)</li><li>【重要】KMP算法的重要特点是主串指针不回溯</li></ul></li></ul><h2 id="排序" tabindex="-1"><a class="header-anchor" href="#排序" aria-hidden="true">#</a> 排序</h2><h3 id="基本概念和定义" tabindex="-1"><a class="header-anchor" href="#基本概念和定义" aria-hidden="true">#</a> 基本概念和定义</h3><ul><li><p>排序：重新排列表中的元素，让表中的元素能够满足按照关键字递增或者递减的过程</p></li><li><p>算法的稳定性【非常重要】</p></li><li><p>排序算法是否具有稳定性并不能衡量一个算法的优劣【重要】</p></li><li><p>内部排序：在排序期间元素全部存放在内存中的排序</p><ul><li>关键字比较</li><li>移动元素</li><li>不是所有的内部排序算法都是基于比较操作的，例如：基数排序属于内部排序算法，但不是基于比较实现的</li></ul></li><li><p>外部排序：在排序期间元素无法全部同时存放在内存中，必须在排序的过程中根据要求不断地在内、外存之间移动的排序。</p></li></ul><h3 id="插入排序" tabindex="-1"><a class="header-anchor" href="#插入排序" aria-hidden="true">#</a> 插入排序</h3><ul><li><p>基本思想：每次将一个待排序的记录，按关键字大小插入到前面已经排序好的子序列中，直到全部记录插入完成</p></li><li><p>直接插入排序</p><ul><li><p>最简单、最直观的插入排序算法</p></li><li><p>性能分析</p><ul><li><p>空间效率：仅仅使用到了常数个辅助单元，空间复杂度为O(1)</p></li><li><p>时间效率：排序过程中，需要向左侧有序子表中逐个插入元素，操作n-1次,每次操作都分为关键字比较和元素移动这两部分的次数非常依赖于待排序表的初始状态【重要】</p><ul><li>最好的情况：元素已经有序，每个元素之需要比较一次，不用移动元素，O(n)</li><li>最坏的情况：元素逆序，比较多次，移动多次，O(n^2)</li><li>平均情况：总的比较次数和总的移动次数均约等于为(n^2)/4 ​</li></ul></li><li><p>稳定性: 【稳定】的排序算法</p></li><li><p>适用性</p><ul><li>顺序存储的线性表</li><li>链式存储的线性表</li><li>大部分排序算法都仅仅适用于顺序存储的线性表【重要】</li></ul></li></ul></li></ul></li><li><p>折半插入排序</p><ul><li><p>简述</p><ul><li><p>直接插入：边比较边移动</p><ul><li>确定插入位置</li><li>腾出空间，元素复制到插入位置</li></ul></li><li><p>折半插入：先比较再统一移动</p><ul><li>确定好待插入的位置后，再统一地向后移动元素</li></ul></li></ul></li><li><p>性能分析</p><ul><li>折半插入排序的比较次数与待排序表的初始状态无关，仅仅取决于表中的元素个数n</li><li>移动元素的次数相比直接插入排序没有任何的改变</li><li>直接插入排序和折半插入排序的比较次数一样，依赖于排序表的初始状态</li><li>时间复杂度：O(n^2)</li><li>稳定性：【稳定】的排序算法</li></ul></li></ul></li><li><p>希尔排序（缩小增量排序）</p><ul><li><p>基本思想：将待排序表分割成为若干个L[i,i+d,i+2d,....,i+kd]的子表，分别进行直接插入排序,当整个表元素“基本有序”的时候，再对全体记录进行一次直接插入排序</p></li><li><p>基本实现步骤</p><ul><li>第一步：取一个小于n的步长d1 ，把待排序的表分成d1个组，所有距离为d1的倍数的记录放在同一个组中，对各组进行直接插入排序</li><li>第二步：取第二个步长d2 &lt; d1，重复第一步</li></ul></li><li><p>主要操作</p><ul><li>确认步长，分组</li><li>对分组元素进行直接插入排序</li></ul></li><li><p>性能分析</p><ul><li><p>空间效率：仅仅使用到了常数个辅助单元，O(1)</p></li><li><p>时间效率</p><ul><li><p>直接插入排序</p><ul><li>是顺序的，时间复杂度最最小，O(n)</li><li>是逆序的，时间复杂度最大，O(n^2)</li><li>是局部有序的，即部分顺序、部分逆序，此时的时间复杂度介于两者之间，O(n)~O(n^2)</li></ul></li><li><p>取决于增量序列函数</p><ul><li>优于折半插入排序</li><li>最坏情况为O(n^2)</li></ul></li></ul></li><li><p>稳定性：【不稳定】，存在相同值元素分在不同的组进行直接插入排序</p></li><li><p>适用性：仅仅适用于顺序存储的线性表，虽然采用过程中有采用直接插入排序，但增量序列不为1的时候，需要随机存取，链式存储的时候无法满足</p></li></ul></li></ul></li></ul><h3 id="交换排序" tabindex="-1"><a class="header-anchor" href="#交换排序" aria-hidden="true">#</a> 交换排序</h3><ul><li><p>冒泡排序</p><ul><li><p>算法简单、思路直接、十分常用但考查少</p></li><li><p>两元素交换方案</p><ul><li>临时变量法</li><li>加减法</li></ul></li><li><p>空间效率</p><ul><li>仅使用了常数个辅助单元</li><li>空间复杂度为O(1)</li></ul></li><li><p>时间效率</p><ul><li><p>最好情况（顺序）</p><ul><li>比较次数：n-1</li><li>移动次数：0</li><li>时间复杂度为：O(n)</li></ul></li><li><p>最坏情况（逆序）</p><ul><li>比较次数：每趟比较(n-i)次</li><li>移动次数：每趟移动3次</li><li>时间复杂度为：O(n^2)</li></ul></li><li><p>时间复杂度为：O(n^2)</p></li></ul></li><li><p>稳定性：【稳定】</p></li></ul></li><li><p>快速排序</p><ul><li><p>基于递归、理解困难、分而治之、关键基准pivot划分</p></li><li><p>空间效率</p><ul><li>基于递归实现，需要借助递归工作栈来保存每一次递归调用的必要信息</li><li>最坏情况：进行n-1次递归，O(n)</li><li>最好情况: log2(n+1) 向上取整</li><li>平均情况： O((n+1)以2为底的对数)</li></ul></li><li><p>时间效率</p><ul><li><p>运行时间与划分操作Partition()函数【不对称相关】</p></li><li><p>最坏情况</p><ul><li>数组长度为n</li><li>左侧快排的数组长度为n-1,有n-1个元素【初始排序表基本有序】</li><li>右侧快排的数组长度为0，有0个元素【初始排序表基本逆序】</li><li>时间复杂度为：O(n^2）</li></ul></li><li><p>效率优化</p><ul><li>递归过程中划分得到的子序列规模较小时候，不再递归调用快速排序 -----&gt;改用直接插入排序【时间复杂度最好O(n),性能好】</li><li>尽量选择能将数据中分的基准值元素</li><li>随机从当前表中选取基准值元素，几乎避免最坏情况的发生</li></ul></li></ul></li><li><p>稳定性：【不稳定】，存在值相同的元素，位置与最终位置不一致情况</p></li><li><p>重要：【是所有内部算法中平均新能最优的排序算法】</p></li></ul></li></ul><h3 id="选择排序-tbd" tabindex="-1"><a class="header-anchor" href="#选择排序-tbd" aria-hidden="true">#</a> 选择排序（TBD）</h3><ul><li>简单选择排序</li><li>堆排序</li></ul><h3 id="归并排序-tbd" tabindex="-1"><a class="header-anchor" href="#归并排序-tbd" aria-hidden="true">#</a> 归并排序（TBD）</h3><h3 id="基数排序" tabindex="-1"><a class="header-anchor" href="#基数排序" aria-hidden="true">#</a> 基数排序</h3><ul><li><p>很特别的排序算法，【不是基于比较进行排序的】</p></li><li><p>基本步骤【趟数取决于元素的最大位数】</p><ul><li>分配：依次考察线性表元素，放入队列中</li><li>收集：各队列中结点一次首尾相接，组成新的线性表</li></ul></li><li><p>分类</p><ul><li>最高位优先排序【MSD】</li><li>最低位优先排序【LSD】</li></ul></li><li><p>性能分析</p><ul><li><p>空间效率：</p><ul><li>一趟排序需要r个队列的辅助存储空间，后续排序这些队列将会复用</li><li>空间复杂度为：O(n)</li></ul></li><li><p>时间效率</p><ul><li><p>进行d趟分配和收集操作</p><ul><li>一趟分配需要O(n)</li><li>一趟收集需要O(r)</li></ul></li><li><p>平均情况：时间复杂度为O(d*(n+r))</p></li><li><p>【重要】算法的时间效率与初始排序表状态无关，依赖于分配和收集操作</p></li></ul></li><li><p>稳定性：【稳定】&lt;----- 按位排序必须稳定</p></li></ul></li></ul><h3 id="内部排序" tabindex="-1"><a class="header-anchor" href="#内部排序" aria-hidden="true">#</a> 内部排序</h3><ul><li><p>各算法性能比较</p><ul><li><p>从时间复杂度来看</p><ul><li><p>平均情况O(n^2)</p><ul><li>直接插入排序</li><li>简单选择排序</li><li>冒泡排序</li></ul></li><li><p>最好情况O(n)【顺序情况】</p><ul><li>直接插入排序</li><li>冒泡排序</li></ul></li><li><p>O(nlog2n)</p><ul><li>归并排序与初始序列的排序列无关，所有情况下时间复杂度都是O(nlog2n)</li><li>堆排序利用数据结构堆，线性时间完成建堆，在O(nlog2n)内完成排序</li><li>快排平均性能可以达到O(nlog2n)【性能常常优于其他排序算法】</li></ul></li><li><p>基于分治法的思想</p><ul><li>快速排序</li><li>归并排序</li></ul></li><li><p>简单选择排序与序列的初始值状态无关</p></li><li><p>希尔排序是插入排序的拓展，在大规模排序中可以达到很高的效率n^1.3~2</p></li></ul></li><li><p>从空间复杂度来看</p><ul><li><p>借助常数个辅助空间</p><ul><li>简单选择排序</li><li>插入排序</li><li>冒泡排序</li><li>希尔排序</li><li>堆排序</li></ul></li><li><p>快速排序在空间上只适用一个小的辅助栈，实现【递归】</p><ul><li>平均情况：O(log2n)</li><li>最坏情况：O(n)</li></ul></li><li><p>二路归并排序需要较多的辅助空间，为O(n)，可以采取时间换空间的思路来减少辅助空间【不建议，导致算法复杂】</p></li></ul></li><li><p>从稳定性来看</p><ul><li><p>稳定的</p><ul><li>插入排序</li><li>冒泡排序</li><li>归并排序</li><li>基数排序</li></ul></li><li><p>不稳定</p><ul><li>简单选择排序</li><li>快速排序</li><li>希尔排序</li><li>堆排序</li></ul></li></ul></li><li><p>从过程特征来看</p><ul><li>冒泡排序和堆排序每次循环都能拿到当前的最大值或最小值</li><li>快速排序每次循环都能确定一个元素到最终位置上</li><li>冒泡排序每一趟冒泡也能确定一个元素到最终位置上</li></ul></li></ul></li><li><p>算法运用</p><ul><li><p>排序方法选取需要考虑的因素</p><ul><li>待排序的元素数目n</li><li>元素本身信息量大小</li><li>关键字的结构和分布情况</li><li>稳定性的要求</li><li>语言工具、存储结构、辅助空间大小</li></ul></li><li><p>排序算法小结</p><ul><li><p>n很小时选择</p><ul><li>直接插入排序</li><li>简单插入排序</li></ul></li><li><p>关键字基本【有序】时选择</p><ul><li>直接插入排序</li><li>冒泡排序</li></ul></li><li><p>n较大时选择O(nlog2n)的排序</p><ul><li>快速排序【不稳定】</li><li>堆排序【不稳定】</li><li>归并排序【稳定】</li></ul></li><li><p>n很大且关键字位较少、可分解，建议选择【基数排序】</p></li><li><p>信息量较大、元素较多，存储结构可以采用【链表】，减少不必要的时间去元素移动</p></li></ul></li><li><p>快速排序被认为是基于比较的内部排序中最好的排序方法</p></li><li><p>基于比较的排序算法中，每次比较两个关键字之后，只有两种情况（大于|小于）----&gt; 二叉树， 时间复杂度至少为O(nlog2n)</p></li></ul></li></ul><h3 id="外部排序" tabindex="-1"><a class="header-anchor" href="#外部排序" aria-hidden="true">#</a> 外部排序</h3><ul><li><p>基本概念</p><ul><li>内部排序：排序方法在内存中进行的排序</li><li>外部排序：排序过程中需要多次进行内存、外存交换，对外存文件中的记录进行排序后【仍然存放在外存原有文件中】的排序</li><li>外部排序原因：对大文件进行排序，内存控件有限，文件中信息量庞大，无法将整个文件拷贝进内存中进行排序，需要多次调入内存进行排序</li></ul></li><li><p>外部排序方法</p><ul><li><p>分类【依据外存设备的不同】</p><ul><li>磁盘文件排序</li><li>磁带文件排序</li></ul></li><li><p>分布方式</p><ul><li>磁盘是直接存取设备</li><li>磁带是顺序存取设备</li></ul></li><li><p>文件通常是【按块存储】在磁盘上，操作系统也是【按块读取】磁盘上的信息</p></li><li><p>外部排序中时间代价主要考虑【访问磁盘的次数】，即I/O次数</p></li><li><p>【通常采用归并排序方法】</p></li></ul></li></ul><h3 id="补充总结和复习" tabindex="-1"><a class="header-anchor" href="#补充总结和复习" aria-hidden="true">#</a> 补充总结和复习</h3><ul><li><p>元素个数不是很大（n&lt;1000）</p><ul><li>直接插入排序【稳定】</li><li>冒泡排序【稳定】</li><li>简单选择排序【不稳定】</li><li>空间复杂度都为O(1)，只需要一个辅助元素</li><li>平均时间复杂度都为O(n^2)</li></ul></li><li><p>中等规模的元素，希尔排序【不稳定】是非常好的选择，比直接插入排序要好（n越大越明显），不占用额外内存空间，减少直接排序次数</p></li><li><p>元素个数很多（n很大）</p><ul><li><p>快速排序【不稳定】</p><ul><li><p>最通用、高效的内部排序算法</p></li><li><p>平均时间复杂度为O(nlog2n)</p></li><li><p>一般空间复杂度为O(log2n)</p></li><li><p>最快情况，性能退化【元素基本有序时】</p><ul><li>时间复杂度提高到O(n^2)</li><li>空间复杂度提高到O(n)</li><li>解决方案： 三者(low,mid,high)取中，获取枢纽值【注意严版采用的是low,high】</li></ul></li></ul></li><li><p>堆排序【不稳定】</p><ul><li>高效的内部排序算法</li><li>时间复杂度为O(nlog2n)</li><li>没啥最坏情况，基本不需要额外的存储空间</li></ul></li><li><p>归并排序【稳定】</p><ul><li>性能与初始化元素序列无关</li><li>时间复杂度总为O(nlog2n)</li><li>【明显缺点】：需要O(n)的额外存储空间</li></ul></li><li><p>基数排序【稳定】</p><ul><li>特殊的排序算法</li><li>除了对元素序列的关键字比较，更对关键字的不同位也进行处理和比较</li><li>具有线性增长的时间复杂度O(d*(n+r))，适用性比较低、应用场景相对少</li><li>需要额外的存储空间，一般用队列来实现桶</li></ul></li></ul></li><li><p>【重要】不同的排序算法缓和使用，往往能够对算法进行不错的改进，获得更好的性能</p></li></ul>',80);function c(s,x){const i=u("Mermaid");return e(),a("div",null,[h,d(i,{id:"mermaid-3",code:"eJzLzcxLyU0s4FJQKMrPL9F4NnXDs951z3dPfjavRRMoCAIaT+fver6w4Wnr0pfTV8AFn+/a/6xh+YuFCJFnCzqeTup5OWP+047pcEE07pMdm5DUT3yyo+/Jrp6n/Z1ANsK62fterNuFUDZ/6bPOfQhu36Snu/o1uQDqU00m"}),t])}const g=p(o,[["render",c],["__file","ds-map.html.vue"]]);export{g as default};
